refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
gray = rgb2gray(image);
features = imdetect_HARRIS(gray, 150, 0.01, 5, 3, 0.04);
imshow(image);
plotfeature(features);
title("Harris corners");

image = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
features = imdetect_HARRIS(image, 100, 0.02, 8, 3, 0.04);
imshow(image);
plotfeature(features);
title("Harris features on fruits");
